      def _render_phrases(subj: str, depth: int = 0) -> list[str]:
          """Return a list of phrase strings for the triples of `subj`.
          For depth == 0 the subject will be omitted (used for sub‑clauses)."""
          phrase_list = []
          for t in subject_map.get(subj, []):
              tmpl = templates.get(t.predicate)
              obj_raw = t.object.strip('"')
              if tmpl:
                  fmt_obj = _fmt_number(obj_raw) if obj_raw.replace(".", "", 1).isdigit() else obj_raw
                  phrase = tmpl.format(obj=fmt_obj)
              else:
                  pred = t.predicate.replace('_', ' ')
                  phrase = f"{pred} {obj_raw}"
              # If we are building a sub‑clause (depth == 1) we do not recurse further
              if depth == 0 and obj_raw in subject_map:
                  # Build a simple sub‑clause for the object
                  sub_phrases = _render_phrases(obj_raw, depth=1)
                  if sub_phrases:
                      # combine sub‑phrases with “and”
                      sub_clause = " and ".join(sub_phrases)
                      phrase = f"{phrase} which {sub_clause}"
              phrase_list.append(phrase)
          return phrase_list

